import "./App.css";
import HelloWorld from "./components/HelloWorld";

function App() {
  const name = "Milton";

  function sum(a, b) {
    return a + b;
  }

  const url = "https://vila.placeholder.com/150";

  return (
    <div className="App">
      <h2> Olá, mundo!</h2>
      <p>Bem-vindo ao meu projeto {name}.</p>
      <p>Soma: {sum(1, 2)}</p>
      <img src={url} alt="Minha Imagem" />
    </div>
  );
}

export default App;
